const https = require('https');
const http = require('http');
const { JSDOM } = require('jsdom');

exports.fetchUrlMetadata = async (req, res) => {
  const url = req.query.url;
  if (!url) {
    res.status(400).send('URL is required');
    return;
  }

  try {
    const data = await fetchHtml(url);
    const metadata = extractMetadata(data);
    res.status(200).json(metadata);
  } catch (error) {
    res.status(500).send('Error fetching metadata');
  }
};

function fetchHtml(url) {
  return new Promise((resolve, reject) => {
    const client = url.startsWith('https') ? https : http;
    client.get(url, (response) => {
      let data = '';
      response.on('data', (chunk) => {
        data += chunk;
      });
      response.on('end', () => {
        resolve(data);
      });
    }).on('error', (err) => {
      reject(err);
    });
  });
}

function extractMetadata(html) {
  const dom = new JSDOM(html);
  const document = dom.window.document;
  const metadata = {};

  metadata.title = document.querySelector('title')?.textContent || '';
  metadata.description = document.querySelector('meta[name="description"]')?.getAttribute('content') || '';
  metadata.openGraph = {};

  const ogTags = document.querySelectorAll('meta[property^="og:"]');
  ogTags.forEach(tag => {
    const property = tag.getAttribute('property');
    const content = tag.getAttribute('content');
    if (property && content) {
      metadata.openGraph[property] = content;
    }
  });

  return metadata;
}